mapper.select:
SELECT id, title, status, close_at, total_pool, created_at FROM market WHERE deleted_at IS NULL
AND status = #{status}
AND title LIKE CONCAT('%', #{keyword}, '%')
ORDER BY created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM market WHERE deleted_at IS NULL
AND status = #{status}
AND title LIKE CONCAT('%', #{keyword}, '%')

SELECT id, market_id, option_code, option_text, display_order, range_min, range_max, min_inclusive, max_inclusive, virtual_pool_amount, real_pool_amount, total_contract_quantity, current_price, prediction_count, is_result, created_at, updated_at FROM market_option WHERE market_id IN
#{marketId}
ORDER BY market_id ASC, display_order ASC, id ASC

SELECT history.id AS history_id, history.option_id, history.price_after AS price, history.real_pool_after AS real_pool_amount, market_option.virtual_pool_amount, history.contract_quantity_after AS contract_quantity, history.created_at FROM market_price_history history JOIN market_option ON market_option.id = history.option_id WHERE history.market_id = #{marketId}
AND history.option_id = #{optionId}
ORDER BY history.created_at DESC, history.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM market_price_history
WHERE market_id = #{marketId}

    AND option_id = #{optionId}
